package com.user.servlet; import com.DB.DBConnect; import com.DAO.*; import com.entity.*; import javax.servlet.annotation.WebServlet; import javax.servlet.http.*; import java.io.*; import java.util.*;
@WebServlet("/order") public class OrderServlet extends HttpServlet {protected void doPost(HttpServletRequest r,HttpServletResponse p)throws IOException{HttpSession s=r.getSession();try(var c=DBConnect.getConn()){int uid=Integer.parseInt(r.getParameter("id"));List<Cart> carts=new CartDAOImpl(c).getBookByUser(uid);if(carts.isEmpty()){s.setAttribute("failedMsg","Cart is empty");p.sendRedirect("checkout.jsp");return;}String full=String.join(", ",r.getParameter("address"),r.getParameter("landmark"),r.getParameter("city"),r.getParameter("state"),r.getParameter("pincode"));String oid="BOOK-ORD-"+String.format("%05d",new Random().nextInt(100000));List<Book_Order> orders=new ArrayList<>();for(Cart x:carts){Book_Order o=new Book_Order();o.setOrderId(oid);o.setUserName(r.getParameter("username"));o.setEmail(r.getParameter("email"));o.setPhno(r.getParameter("phono"));o.setFulladd(full);o.setBookName(x.getBookName());o.setAuthor(x.getAuthor());o.setPrice(String.valueOf(x.getPrice()));o.setPaymentType("cod".equalsIgnoreCase(r.getParameter("payment"))?"COD":r.getParameter("payment"));orders.add(o);}if(new BookOrderImpl(c).saveOrder(orders)){try(PreparedStatementHack h=new PreparedStatementHack(c,"DELETE FROM cart WHERE uid=?",uid)){h.execute();}p.sendRedirect("order_success.jsp");}else{s.setAttribute("failedMsg","Order failed");p.sendRedirect("checkout.jsp");}}catch(Exception e){s.setAttribute("failedMsg",e.getMessage());p.sendRedirect("checkout.jsp");}}
 private static class PreparedStatementHack implements AutoCloseable{private final java.sql.PreparedStatement p;PreparedStatementHack(java.sql.Connection c,String q,int id)throws Exception{p=c.prepareStatement(q);p.setInt(1,id);}void execute()throws Exception{p.executeUpdate();}public void close()throws Exception{p.close();}}
}
